import{_ as t,c as p,o as r,d as e}from"./app.661b9247.js";const T=JSON.parse('{"title":"1-初识TypeScript","description":"","frontmatter":{},"headers":[{"level":2,"title":"TypeScript 的介绍","slug":"typescript-的介绍","link":"#typescript-的介绍","children":[]},{"level":2,"title":"TypeScript 的特点","slug":"typescript-的特点","link":"#typescript-的特点","children":[]},{"level":2,"title":"总结","slug":"总结","link":"#总结","children":[]}],"relativePath":"Document/TypeScript/TypeScript开发前置/1-初识TypeScript.md","lastUpdated":1672864685000}'),i={name:"Document/TypeScript/TypeScript开发前置/1-初识TypeScript.md"},c=e('<h1 id="_1-初识typescript" tabindex="-1">1-初识TypeScript <a class="header-anchor" href="#_1-初识typescript" aria-hidden="true">#</a></h1><p>菜鸟教程-TypeScript教程文档：<a href="https://www.runoob.com/typescript/ts-tutorial.html" target="_blank" rel="noreferrer">https://www.runoob.com/typescript/ts-tutorial.html</a></p><hr><p><img src="https://p6-juejin.byteimg.com/tos-cn-i-k3u1fbpfcp/28ca61cc160c417c8497a00defdca5f0~tplv-k3u1fbpfcp-watermark.image" alt="TS与JS.png"></p><h2 id="typescript-的介绍" tabindex="-1">TypeScript 的介绍 <a class="header-anchor" href="#typescript-的介绍" aria-hidden="true">#</a></h2><p>TypeScript 是一种由微软开发的开源、跨平台的编程语言。它是 JavaScript 的超集，最终会被编译为 JavaScript 代码。</p><p>2012 年 10 月，微软发布了首个公开版本的 TypeScript，2013 年 6 月 19 日，在经历了一个预览版之后微软正式发布了正式版 TypeScript</p><p>TypeScript 的作者是安德斯·海尔斯伯格，C#的首席架构师。它是开源和跨平台的编程语言。</p><p>TypeScript 扩展了 JavaScript 的语法，所以任何现有的 JavaScript 程序可以运行在 TypeScript 环境中。</p><p>TypeScript 是为大型应用的开发而设计，并且可以编译为 JavaScript。</p><p>TypeScript 是 JavaScript 的一个超集，主要提供了类型系统和对 ES6+ 的支持**，它由 Microsoft 开发，代码开源于 GitHub 上</p><p><strong>TypeScript 是 JavaScript 的一个超集</strong>，主要提供了<strong>类型系统</strong>和<strong>对 ES6+ 的支持</strong>，它由 Microsoft 开发，代码<a href="https://github.com/Microsoft/TypeScript" target="_blank" rel="noreferrer">开源于 GitHub</a> 上</p><h2 id="typescript-的特点" tabindex="-1">TypeScript 的特点 <a class="header-anchor" href="#typescript-的特点" aria-hidden="true">#</a></h2><p>TypeScript 主要有 3 大特点：</p><ul><li><strong>始于 JavaScript，归于 JavaScript</strong></li></ul><p>TypeScript 可以编译出纯净、 简洁的 JavaScript 代码，并且可以运行在任何浏览器上、Node.js 环境中和任何支持 ECMAScript 3（或更高版本）的 JavaScript 引擎中。</p><ul><li><strong>强大的类型系统</strong></li></ul><p><strong>类型系统</strong>允许 JavaScript 开发者在开发 JavaScript 应用程序时使用高效的开发工具和常用操作比如静态检查和代码重构。</p><ul><li><strong>先进的 JavaScript</strong></li></ul><p>TypeScript 提供最新的和不断发展的 JavaScript 特性，包括那些来自 2015 年的 ECMAScript 和未来的提案中的特性，比如异步功能和 Decorators，以帮助建立健壮的组件。</p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-hidden="true">#</a></h2><p>TypeScript 在社区的流行度越来越高，它非常适用于一些大型项目，也非常适用于一些基础库，极大地帮助我们提升了开发效率和体验。</p>',22),a=[c];function s(o,n,S,l,h,d){return r(),p("div",null,a)}const _=t(i,[["render",s]]);export{T as __pageData,_ as default};
